function EmailWatcher() {
  const [mail, setMail] = React.useState([]);
  const [busy, setBusy] = React.useState(false);
  const [summarizing, setSummarizing] = React.useState(null);
  const [summary, setSummary] = React.useState({});
  const [error, setError] = React.useState('');
  const refresh = async () => {
    setBusy(true);
    try {
      const r = await titan.api.call('/api/skills/email', { method: 'POST', body: { action: 'list', folder: 'INBOX', unreadOnly: true, max: 20 } });
      setMail(Array.isArray(r?.messages) ? r.messages : []);
      setError('');
    } catch (e) { setError(String(e?.message||e)); }
    finally { setBusy(false); }
  };
  React.useEffect(() => { refresh(); const id = setInterval(refresh, 120000); return () => clearInterval(id); }, []);
  const summarize = async (m) => {
    setSummarizing(m.id);
    try {
      const r = await titan.api.call('/api/message', { method: 'POST', body: { content: `Summarize this email in 2 sentences:\n\nFrom: ${m.from}\nSubject: ${m.subject}\n\n${m.body || m.snippet || ''}` } });
      setSummary(s => ({ ...s, [m.id]: r?.content || r?.text || JSON.stringify(r) }));
    } catch (e) { setSummary(s => ({ ...s, [m.id]: 'Error: ' + (e?.message||e) })); }
    finally { setSummarizing(null); }
  };
  return (
    <div style={{padding:12,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',gap:8,alignItems:'center',marginBottom:8}}>
        <div style={{fontSize:16,fontWeight:600,flex:1}}>📬 Unread ({mail.length})</div>
        <button onClick={refresh} disabled={busy} style={{padding:'6px 12px',borderRadius:6,border:'1px solid #ccc',background:'#fff',cursor:busy?'wait':'pointer'}}>{busy?'…':'↻'}</button>
      </div>
      {error && <div style={{color:'#FF3B30',fontSize:12,marginBottom:6}}>{error}</div>}
      <div style={{flex:1,overflow:'auto'}}>
        {mail.length === 0 ? <div style={{textAlign:'center',color:'#888',padding:30}}>{error?'Email skill needs configuring.':'Inbox zero ✨'}</div> :
          mail.map((m,i) => (
            <div key={m.id||i} style={{padding:10,marginBottom:6,background:'#f9f9f9',borderRadius:8}}>
              <div style={{fontSize:12,color:'#666'}}>{m.from}</div>
              <div style={{fontSize:13,fontWeight:600,margin:'2px 0'}}>{m.subject}</div>
              <div style={{fontSize:11,color:'#888'}}>{m.snippet}</div>
              {summary[m.id] && <div style={{marginTop:6,padding:8,background:'#FFF7E6',borderRadius:6,fontSize:12,color:'#444'}}>✨ {summary[m.id]}</div>}
              <button onClick={()=>summarize(m)} disabled={summarizing===m.id} style={{marginTop:6,padding:'4px 10px',border:'1px solid #ddd',background:'#fff',borderRadius:4,fontSize:11,cursor:summarizing===m.id?'wait':'pointer'}}>{summarizing===m.id?'Summarizing…':'✨ Summarize'}</button>
            </div>
          ))
        }
      </div>
    </div>
  );
}
render(<EmailWatcher/>);
